package org.apache.commons.math.analysis.solvers;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.analysis.solvers.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math.analysis.solvers.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.analysis.UnivariateFunction;
import org.apache.commons.math.analysis.solvers.RegulaFalsiSolver;
import org.apache.commons.math.exception.MaxEvaluationsExceededException;
import static org.junit.Assert.*;

public class StepDefs {
    private RegulaFalsiSolver solver;
    private double root;
    private boolean exceptionThrown;

    public static class ExponentialMinusCubeOfPi implements UnivariateFunction {
        @Override
        public double value(double x) {
            return Math.exp(x) - Math.pow(Math.PI, 3);
        }
    }

    @Given("a Regula Falsi solver is initialized")
    public void a_Regula_Falsi_solver_is_initialized() {
        solver = new RegulaFalsiSolver();
        exceptionThrown = false;
    }

    @When("it is used to solve the function \"f(x) = exp(x) - pi^3\" in the interval [1, 10]")
    public void it_is_used_to_solve_the_function_in_the_interval() {
        try {
            root = solver.solve(1000, new ExponentialMinusCubeOfPi(), 1, 10);
        } catch (MaxEvaluationsExceededException e) {
            exceptionThrown = true;
        }
    }

    @When("the maximum number of evaluations is set to {int}")
    public void the_maximum_number_of_evaluations_is_set_to(int maxEvaluations) {
        try {
            root = solver.solve(maxEvaluations, new ExponentialMinusCubeOfPi(), 1, 10);
        } catch (MaxEvaluationsExceededException e) {
            exceptionThrown = true;
        }
    }

    @Then("the solver should find the root approximately {double}")
    public void the_solver_should_find_the_root_approximately(double expectedRoot) {
        assertEquals(expectedRoot, root, 1e-10);
    }

    @Then("it should not throw a MaxEvaluationsExceededException")
    public void it_should_not_throw_a_MaxEvaluationsExceededException() {
        assertFalse("MaxEvaluationsExceededException was thrown", exceptionThrown);
    }
}

